#include<bits/stdc++.h>
using namespace std;
const int mod1=998244353,mod2=1e9+7,p=131;
int n;
unordered_map<long long,int> mp;
int fastpow(int x,int y,int mod)
{
    int ans=1;
    while(y)
    {
        if(y%2==1)
        {
            ans=1ll*ans*x%mod;
        }
        x=1ll*x*x%mod;
        y/=2;
    }
    return ans;
}
int main()
{
    scanf("%d",&n);
    long long ans=0;
    for(int i=1;i<=n;i++)
    {
        int c;
        scanf("%d",&c);
        long long s1=0,t1=1,s2=0,t2=1;
        while(c--)
        {
            char ch;
            cin>>ch;
            t1=t1*p%mod1;
            s1=(s1*p+ch)%mod1;
            t2=t2*p%mod2;
            s2=(s2*p+ch)%mod2;
        }
        s1=s1*fastpow(t1-1,mod1-2,mod1)%mod1;
        s2=s2*fastpow(t2-1,mod2-2,mod2)%mod2;
        ans+=mp[s1*mod2+s2];
        mp[s1*mod2+s2]++;
    }
    printf("%lld",ans*2+n);
    return 0;
}
